#[php_class]
#[php(name = "Liter\\Llm\\LiterLlmApi")]
pub struct LiterLlmApi;

#[php_impl]
impl LiterLlmApi {
    /**
     * Create a new LLM client with simple scalar configuration.
     *
     * This is the primary binding entry-point. All parameters except `api_key`
     * are optional — omitting them uses the same defaults as
     * `ClientConfigBuilder`.
     * @throws LiterLlmException Returns `LiterLlmError` if the underlying HTTP client cannot be
     * constructed, or if the resolved provider configuration is invalid.
     */
    #[php(name = "createClient")]
    pub fn create_client(
        apiKey: String,
        baseUrl: Option<String>,
        timeoutSecs: Option<i64>,
        maxRetries: Option<u32>,
        modelHint: Option<String>,
    ) -> PhpResult<DefaultClient> {
        let result = liter_llm::create_client(apiKey, baseUrl, timeoutSecs.map(|v| v as u64), maxRetries, modelHint)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(DefaultClient {
            inner: Arc::new(result),
        })
    }

    /**
     * Create a new LLM client from a JSON string.
     *
     * The JSON object accepts the same fields as `liter-llm.toml` (snake_case).
     * @throws LiterLlmException Returns `LiterLlmError.BadRequest` if `json` is not valid JSON or
     * contains unknown fields.
     */
    #[php(name = "createClientFromJson")]
    pub fn create_client_from_json(json: String) -> PhpResult<DefaultClient> {
        let result = liter_llm::create_client_from_json(&json)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(DefaultClient {
            inner: Arc::new(result),
        })
    }

    /**
     * Register a custom provider in the global runtime registry.
     *
     * The provider will be checked **before** all built-in providers during model
     * detection. If a provider with the same `name` already exists it is replaced.
     * @throws LiterLlmException Returns an error if the config is invalid (empty name, empty base_url, or
     * no model prefixes).
     */
    #[php(name = "registerCustomProvider")]
    pub fn register_custom_provider(config: &CustomProviderConfig) -> PhpResult<()> {
        let config_core: liter_llm::CustomProviderConfig = config.clone().into();
        let result = liter_llm::provider::custom::register_custom_provider(config_core)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    /**
     * Remove a previously registered custom provider by name.
     *
     * Returns `true` if a provider with the given name was found and removed,
     * `false` if no such provider existed.
     * @throws LiterLlmException Returns an error only if the internal lock is poisoned.
     */
    #[php(name = "unregisterCustomProvider")]
    pub fn unregister_custom_provider(name: String) -> PhpResult<bool> {
        let result = liter_llm::provider::custom::unregister_custom_provider(&name)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    /**
     * Return all provider configs from the registry.
     *
     * Useful for tooling, documentation generation, or runtime enumeration.
     */
    #[php(name = "allProviders")]
    pub fn all_providers() -> PhpResult<Vec<ProviderConfig>> {
        let result = liter_llm::provider::all_providers()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result.iter().cloned().map(Into::into).collect())
    }

    /**
     * Return the set of complex provider names.
     *
     * Complex providers require custom auth/routing logic beyond simple bearer
     * tokens (e.g. AWS Bedrock SigV4, Vertex AI OAuth2).
     *
     * The returned reference points into the static registry — no allocation.
     */
    #[php(name = "complexProviderNames")]
    pub fn complex_provider_names() -> PhpResult<Vec<String>> {
        let result = liter_llm::provider::complex_provider_names()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result.iter().map(|s| s.to_string()).collect())
    }

    /**
     * Calculate the estimated cost of a completion given a model name and token
     * counts.
     *
     * Returns `None` if the model is not present in the embedded pricing registry.
     * Returns `Some(cost_usd)` otherwise, where the value is in US dollars.
     *
     * When an exact model name match is not found, progressively shorter prefixes
     * are tried by stripping from the last `-` or `.` separator.  For example,
     * `gpt-4-0613` will match `gpt-4` if no `gpt-4-0613` entry exists.
     *
     * # Example
     */
    #[php(name = "completionCost")]
    pub fn completion_cost(model: String, promptTokens: i64, completionTokens: i64) -> Option<f64> {
        liter_llm::completion_cost(&model, promptTokens as u64, completionTokens as u64)
    }

    /**
     * Calculate the estimated cost of a completion, accounting for cached
     * (cache-hit) prompt tokens billed at the provider's discounted rate.
     *
     * `cached_tokens` is the count of prompt tokens served from the provider's
     * prompt cache. It must be `<= prompt_tokens` (cached tokens are a subset of
     * the prompt). The non-cached portion is billed at `input_cost_per_token`
     * and the cached portion at `cache_read_input_token_cost` when the model
     * has cache pricing; otherwise the entire prompt is billed at the regular
     * input rate.
     *
     * Returns `None` if the model is not present in the embedded pricing
     * registry, mirroring `completion_cost`.
     */
    #[php(name = "completionCostWithCache")]
    pub fn completion_cost_with_cache(
        model: String,
        promptTokens: i64,
        cachedTokens: i64,
        completionTokens: i64,
    ) -> Option<f64> {
        liter_llm::completion_cost_with_cache(
            &model,
            promptTokens as u64,
            cachedTokens as u64,
            completionTokens as u64,
        )
    }

    /**
     * Count tokens in a text string using the tokenizer for the given model.
     *
     * The tokenizer is resolved from the model name prefix (e.g. `"gpt-4o"` maps
     * to the `Xenova/gpt-4o` HuggingFace tokenizer). Tokenizers are cached after
     * first load.
     * @throws LiterLlmException Returns `LiterLlmError.BadRequest` if the tokenizer cannot be loaded
     * (e.g. network failure on first use) or if tokenization itself fails.
     */
    #[php(name = "countTokens")]
    pub fn count_tokens(model: String, text: String) -> PhpResult<i64> {
        let result = liter_llm::count_tokens(&model, &text)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result as i64)
    }

    /**
     * Count tokens for a full `ChatCompletionRequest`.
     *
     * Sums tokens across all message text contents plus a per-message overhead
     * of ~4 tokens (for role, separators, and formatting metadata). Tool
     * definitions and multimodal content parts (images, audio, documents) are
     * not counted — only textual content contributes to the token total.
     * @throws LiterLlmException Returns `LiterLlmError.BadRequest` if the tokenizer cannot be loaded or
     * if tokenization fails for any message.
     */
    #[php(name = "countRequestTokens")]
    pub fn count_request_tokens(model: String, req: Option<&ChatCompletionRequest>) -> PhpResult<i64> {
        let req_core: Option<liter_llm::ChatCompletionRequest> = req.map(|v| v.clone().into());
        let result = liter_llm::count_request_tokens(&model, &req_core.unwrap_or_default())
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result as i64)
    }

    /**
     * Install the `ring` crypto provider as the rustls process default, idempotently.
     *
     * rustls 0.23+ removed the implicit default provider. This function installs
     * `ring` once per process. Subsequent calls are no-ops. Calling it from a
     * downstream Rust app that has already installed `aws-lc-rs` is safe — the
     * `Err` from `install_default()` is silently ignored.
     *
     * Called automatically by every internal `reqwest.Client` constructor
     * (auth providers, default HTTP client). Bindings and downstream consumers
     * reach those constructors transitively, so no manual init is required.
     *
     * WASM builds are exempt — the WASM target uses the browser/Node.js fetch
     * API instead of rustls, so no crypto provider is needed.
     *
     * Windows builds use native-tls (SChannel) via reqwest, so rustls is not
     * present and no crypto provider installation is needed.
     */
    #[php(name = "ensureCryptoProvider")]
    pub fn ensure_crypto_provider() {
        liter_llm::ensure_crypto_provider()
    }

    #[php(name = "chatStream")]
    pub fn chatStream(
        engine: &DefaultClient,
        req: &ChatCompletionRequest,
    ) -> std::result::Result<Vec<String>, ext_php_rs::exception::PhpException> {
        engine.chat_stream(&req)
    }
}

